int c2n(int x) {
    return x * (x - 1) / 2;
}

struct disjoinset{
    int par[MAXN], cnt[MAXN];
    void init(){
        For(i,1,n){
            par[i] = -1;
        }
    }

    int find(int u){
        return par[u] < 0 ? u : par[u] = find(par[u]);
    }

    int size(int u){
        return -par[find(u)];
    }

    int calc(int u){
        return c2n(size(u));
    }

    int merge(int u,int v){
        u = find(u); v = find(v);
        if(u == v) return u;
        if(par[u] > par[v]) swap(u,v);
        par[u] += par[v];
        par[v] = u;
        return u;
    }
} dsu;

struct Edges{
    int u, v, w;
};
vector<Edges> E;

